import{c as r,Q as e,j as o,m as s}from"./chunks/framework.BXc4yaFE.js";const p=JSON.parse('{"title":"Model-Harness-Fit (MHF) Research Digest","description":"","frontmatter":{"title":"Model-Harness-Fit (MHF) Research Digest","type":"documentation"},"headers":[],"relativePath":"research/ai-articles/MHF-RESEARCH-DIGEST.md","filePath":"research/ai-articles/MHF-RESEARCH-DIGEST.md","lastUpdated":1779894392000}'),n={name:"research/ai-articles/MHF-RESEARCH-DIGEST.md"};function a(i,t,l,d,g,h){return e(),o("div",null,[...t[0]||(t[0]=[s('<h1 id="model-harness-fit-mhf-research-digest" tabindex="-1">Model-Harness-Fit (MHF) Research Digest <a class="header-anchor" href="#model-harness-fit-mhf-research-digest" aria-label="Permalink to &quot;Model-Harness-Fit (MHF) Research Digest&quot;">​</a></h1><p><strong>編製日期</strong>：2026-05-09<br><strong>來源數</strong>：7 篇學術+業界<br><strong>平均評分</strong>：7.91/10<br><strong>範圍</strong>：Anthropic、Cursor、OpenAI/Codex、LangChain、Terminal-Bench、Arbiter cross-vendor analysis</p><hr><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p>Model-Harness-Fit (MHF) 是 2026 年 agent 設計中最被低估的約束。核心論點：模型在 post-training 中已對特定 harness（系統提示結構、工具 schema、記憶儀式、引用規約）達成 byte-level 過擬合。跨 harness 移植模型 = 隱性效能崩塌，即使 logits 相同。</p><hr><h2 id="收集的來源-按評分排序" tabindex="-1">收集的來源（按評分排序） <a class="header-anchor" href="#收集的來源-按評分排序" aria-label="Permalink to &quot;收集的來源（按評分排序）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>#</th><th>標題</th><th>來源</th><th>評分</th><th>關鍵發現</th></tr></thead><tbody><tr><td>1</td><td>LangChain: Deep Agents Harness Engineering</td><td>LangChain Blog</td><td><strong>8.2</strong></td><td>13.7pt (+52.8→66.5%) on TB2.0 via reasoning sandwich + middleware；無模型改變</td></tr><tr><td>2</td><td>Cursor: Continually Improving Agent Harness</td><td>Cursor Blog</td><td><strong>8.0</strong></td><td>Model-specific tool provisioning（patch vs string replace）；Keep Rate A/B 量化</td></tr><tr><td>3</td><td>Anthropic: April-23 Postmortem (Claude Code)</td><td>Anthropic Eng Blog</td><td><strong>7.8</strong></td><td>Harness 變更累積致 3% 品質下滑；per-model eval suite 必須</td></tr><tr><td>4</td><td>Anthropic: Harness Design Long-Running Apps</td><td>Anthropic Eng Blog</td><td><strong>7.65</strong></td><td>Co-evolution feedback loop；harness 元件隨模型成熟過時</td></tr><tr><td>5</td><td>Arbiter: System Prompt Interference Analysis</td><td>arXiv 2603.08993</td><td><strong>8.0</strong></td><td>三種 harness 架構（monolithic/flat/modular）導致不同失敗模態；$0.27 cross-vendor audit</td></tr><tr><td>6</td><td>Terminal-Bench 2.0</td><td>arXiv 2601.11868</td><td><strong>7.6</strong></td><td>Harness impact ≥ model upgrade；ForgeCode (3rd-party) 在 top-6 佔 3 席</td></tr><tr><td>7</td><td>V4A Diff Format (Codex)</td><td>Codex Blog</td><td><strong>7.5</strong></td><td>Tool format as post-training habit；Azure GPT-4.1 缺 V4A training → unreliable</td></tr></tbody></table><hr><h2 id="跨來源主題匯流" tabindex="-1">跨來源主題匯流 <a class="header-anchor" href="#跨來源主題匯流" aria-label="Permalink to &quot;跨來源主題匯流&quot;">​</a></h2><h3 id="_1-harness-impact-量化証證" tabindex="-1">1. <strong>Harness Impact 量化証證</strong> <a class="header-anchor" href="#_1-harness-impact-量化証證" aria-label="Permalink to &quot;1. **Harness Impact 量化証證**&quot;">​</a></h3><p><strong>獨立來源匯流</strong>：LangChain、Cursor、Terminal-Bench、Anthropic postmortem</p><ul><li><strong>LangChain</strong>：無模型改變，harness 改動 +13.7pt</li><li><strong>Cursor</strong>：Top 30 → Top 5（25 名躍升）via harness-only</li><li><strong>Terminal-Bench 2.0</strong>：同 Opus 4.6，ForgeCode 79.8% vs Capy 75.3%（4.5pt 差異）</li><li><strong>Anthropic</strong>：System prompt 改動 -3%（無模型版本改變）</li></ul><p><strong>結論</strong>：Harness 對分數的邊際貢獻 ≈ 或 &gt; 模型世代升級。</p><h3 id="_2-tool-surface-為-post-training-的-byte-level-習慣" tabindex="-1">2. <strong>Tool Surface 為 Post-Training 的 Byte-Level 習慣</strong> <a class="header-anchor" href="#_2-tool-surface-為-post-training-的-byte-level-習慣" aria-label="Permalink to &quot;2. **Tool Surface 為 Post-Training 的 Byte-Level 習慣**&quot;">​</a></h3><p><strong>獨立來源</strong>：Cursor、V4A format blog、推文 @nicbstme</p><ul><li><strong>Cursor</strong>：OpenAI models trained on V4A patch → 給 <code>apply_patch</code> 工具；Claude trained on string-replace → 給 <code>Edit</code></li><li><strong>V4A 深度分析</strong>：OpenAI 在 GPT-5.x 進行「significant training effort」專為 V4A。Azure GPT-4.1（未特化）移除 V4A prompt 後 → 無法可靠生成</li><li><strong>Codex blog 結論</strong>：「Format is part of the model&#39;s effective parameters」</li></ul><p><strong>結論</strong>：跨模型移植工具設計會增加 reasoning tokens 並提升錯誤率。</p><h3 id="_3-system-prompt-架構決定失敗模式類型" tabindex="-1">3. <strong>System Prompt 架構決定失敗模式類型</strong> <a class="header-anchor" href="#_3-system-prompt-架構決定失敗模式類型" aria-label="Permalink to &quot;3. **System Prompt 架構決定失敗模式類型**&quot;">​</a></h3><p><strong>來源</strong>：Arbiter 論文、Anthropic postmortem</p><ul><li><strong>Arbiter</strong>：Monolithic（Claude Code）vs Flat（Codex）vs Modular（Gemini）各有特異的矛盾類型 <ul><li>Monolithic：subsystem 矛盾累積（4 critical contradictions in Claude Code）</li><li>Modular：composition seams 設計漏洞（Gemini history compression data loss）</li></ul></li><li><strong>Anthropic postmortem</strong>：System prompt 字數限制 → -3% 品質（看似無害實則傷害編碼能力）</li></ul><p><strong>結論</strong>：架構選擇 → 失敗模態分佈 → 模型被訓練去平衡該架構的內在矛盾。</p><h3 id="_4-harness-元件隨模型進化過時" tabindex="-1">4. <strong>Harness 元件隨模型進化過時</strong> <a class="header-anchor" href="#_4-harness-元件隨模型進化過時" aria-label="Permalink to &quot;4. **Harness 元件隨模型進化過時**&quot;">​</a></h3><p><strong>來源</strong>：Anthropic harness design + postmortem</p><ul><li><strong>設計原則</strong>：「Every component encodes an assumption about what the model can&#39;t do on its own」</li><li><strong>Opus 4.6 vs 4.5</strong>：Context reset machinery 在 4.5 load-bearing，在 4.6 變成 dead weight</li><li><strong>Postmortem</strong>：Reasoning effort default 從 high → medium 的嘗試，在 Opus 4.7 需要回復為 xhigh</li><li><strong>發現</strong>：模型能力進化使舊假設失效；harness 年度審計必須檢查哪些元件仍需要</li></ul><p><strong>結論</strong>：Harness 不是「建一次就永遠用」，而是「追蹤模型進化重新評估」。</p><h3 id="_5-多代理分工-pge-的性能躍升" tabindex="-1">5. <strong>多代理分工（PGE）的性能躍升</strong> <a class="header-anchor" href="#_5-多代理分工-pge-的性能躍升" aria-label="Permalink to &quot;5. **多代理分工（PGE）的性能躍升**&quot;">​</a></h3><p><strong>來源</strong>：Anthropic 三代理設計、LangChain middleware hooks</p><ul><li><strong>Anthropic 實例</strong>：Planner-Generator-Evaluator 在長時間任務實現「完全破損 → 完整可玩」的躍升</li><li><strong>LangChain 實例</strong>：Middleware（LocalContext、PreCompletionChecklist、LoopDetection）各自檢測不同失敗模式</li></ul><p><strong>結論</strong>：PGE 拓撲不是「nice-to-have」而是「必要」去達到前沿自主度。</p><h3 id="_6-reasoning-budget-分配的非線性效應" tabindex="-1">6. <strong>Reasoning Budget 分配的非線性效應</strong> <a class="header-anchor" href="#_6-reasoning-budget-分配的非線性效應" aria-label="Permalink to &quot;6. **Reasoning Budget 分配的非線性效應**&quot;">​</a></h3><p><strong>來源</strong>：LangChain「reasoning sandwich」</p><ul><li><strong>Naive xhigh everywhere</strong>：53.9%（超時）</li><li><strong>High only</strong>：63.6%</li><li><strong>xhigh (plan) + high (implement) + xhigh (verify)</strong>：66.5%</li></ul><p><strong>發現</strong>：不同任務階段的 reasoning 需求不對稱；靜態配置次優。</p><p><strong>結論</strong>：動態 reasoning budget allocation 相較「maxout all」更有效且低成本。</p><h3 id="_7-跨廠商互補分析的新發現" tabindex="-1">7. <strong>跨廠商互補分析的新發現</strong> <a class="header-anchor" href="#_7-跨廠商互補分析的新發現" aria-label="Permalink to &quot;7. **跨廠商互補分析的新發現**&quot;">​</a></h3><p><strong>來源</strong>：Arbiter 論文</p><ul><li>10 個模型對 116 項發現生成 107 個獨特分類</li><li>Kimi K2.5 的「經濟/資源視角」在 Claude Opus 的分析中完全缺席</li><li><strong>成本</strong>：$0.27 USD + 三小時評審</li><li><strong>驗證</strong>：Gemini history loss 獨立被 Google 確認為真實 bug</li></ul><p><strong>結論</strong>：多模型審查並非浪費，而是發現型號特定盲點的必要。</p><hr><h2 id="對立觀點-若存在" tabindex="-1">對立觀點（若存在） <a class="header-anchor" href="#對立觀點-若存在" aria-label="Permalink to &quot;對立觀點（若存在）&quot;">​</a></h2><h3 id="反方-i-自然語言-agent-harnesses-nlah-聲稱可實現跨模型可移植" tabindex="-1"><strong>反方 I：自然語言 Agent Harnesses (NLAH) 聲稱可實現跨模型可移植</strong> <a class="header-anchor" href="#反方-i-自然語言-agent-harnesses-nlah-聲稱可實現跨模型可移植" aria-label="Permalink to &quot;**反方 I：自然語言 Agent Harnesses (NLAH) 聲稱可實現跨模型可移植**&quot;">​</a></h3><p><strong>主張</strong>：透過外部化 harness 為自然語言制品（而非 code），可在不同執行環境間轉移。</p><p><strong>證據品質分析</strong>：</p><ul><li><strong>實驗限制</strong>：所有評估 exclusively on GPT-5.4（未測多模型）</li><li><strong>Porting 效果</strong>：47.2% (NLAH) vs 30.4% (native)，但這反映「行為重配置」而非「模式無關性」</li><li><strong>機制局限</strong>：自然語言無法捕捉「隱藏的服務端狀態、專有調度器、訓練導出行為」</li></ul><p><strong>評估</strong>：反方論文強度較弱，未驗證跨模型的真實可移植性，僅展示單一模型內的口述 harness。</p><h3 id="反方-ii-model-context-protocol-mcp-作為統一層" tabindex="-1"><strong>反方 II：Model Context Protocol (MCP) 作為統一層</strong> <a class="header-anchor" href="#反方-ii-model-context-protocol-mcp-作為統一層" aria-label="Permalink to &quot;**反方 II：Model Context Protocol (MCP) 作為統一層**&quot;">​</a></h3><p><strong>主張</strong>：MCP 使任何宿主能連接任何 MCP 伺服器，regardless of 底層模型。</p><p><strong>現狀</strong>：</p><ul><li>Google 2026 推出 managed MCP endpoints（IAM、audit logging）</li><li>LangChain 引入「harness profiles」per-model</li></ul><p><strong>評估</strong>：MCP 解決了「工具發現」層，但不解決「tool schema shape」層的過擬合。Cursor 的實踐表明：即使透過 MCP，仍需 per-model tool inclusion（Codex 給 apply_patch、Claude 給 Edit）。</p><p><strong>結論</strong>：MCP 是必要非充分條件；harness 仍需 model-specific 調整。</p><hr><h2 id="cc-workspace-直接行動建議" tabindex="-1">CC-Workspace 直接行動建議 <a class="header-anchor" href="#cc-workspace-直接行動建議" aria-label="Permalink to &quot;CC-Workspace 直接行動建議&quot;">​</a></h2><h3 id="a-優先級高-立即可行" tabindex="-1">A. <strong>優先級高（立即可行）</strong> <a class="header-anchor" href="#a-優先級高-立即可行" aria-label="Permalink to &quot;A. **優先級高（立即可行）**&quot;">​</a></h3><ol><li><p><strong>Per-Model Evaluation Suite</strong><br> 路徑：<code>.claude/refs/quality.md</code> § Benchmark Evaluation<br> 行動：為 Haiku 4.5 / Sonnet 4.6 / Opus 4.7 維持獨立的 test case 套組<br> 來源：Anthropic postmortem（per-model suite 防止回歸）</p></li><li><p><strong>System Prompt Ablation Gate</strong><br> 路徑：<code>.claude/rules/core.md</code> § System Prompt Changes<br> 行動：CLAUDE.md 或 <code>.claude/rules/</code> 改動時，執行「change × each model」ablation<br> 來源：Anthropic postmortem（字數限制無意中 -3%）+ Arbiter（架構矛盾檢測）</p></li><li><p><strong>Harness Obsolescence Audit Framework</strong><br> 路徑：<code>.claude/refs/harness-design.md</code> § Component Lifecycle<br> 行動：年度檢查「這項 harness 元件還在補哪個模型的缺口？還是 dead weight？」<br> 來源：Anthropic 設計原則（context reset machinery 在 Opus 4.6 過時）</p></li></ol><h3 id="b-優先級中-設計階段" tabindex="-1">B. <strong>優先級中（設計階段）</strong> <a class="header-anchor" href="#b-優先級中-設計階段" aria-label="Permalink to &quot;B. **優先級中（設計階段）**&quot;">​</a></h3><ol start="4"><li><p><strong>Reasoning Sandwich 在 Opus Pilot Mode 中的應用</strong><br> 路徑：<code>.claude/skills/opus-pilot/prompt.md</code><br> 建議：「plan: xhigh, implement: high, verify: xhigh」作推薦配置<br> 來源：LangChain +13.7pt 驗證</p></li><li><p><strong>Tool Reliability 監測指標</strong><br> 路徑：<code>.claude/refs/</code> 新檔 <code>tool-reliability.md</code><br> 建議：Read/Write/Edit/Bash/Monitor 的 error-rate 基準（Cursor 達成 2-3 9s）<br> 來源：Cursor A/B test 文化</p></li><li><p><strong>Model-Specific Tool Provisioning 文件化</strong><br> 路徑：<code>.claude/refs/model-selection-grid.md</code> § Tool Surface<br> 確認：Haiku/Sonnet/Opus 各自的工具優選（Claude 系列都是 string-replace，所以目前無差異；但如未來支援 Codex，需此層）<br> 來源：Cursor + V4A format 分析</p></li></ol><h3 id="c-優先級低-長期-roadmap" tabindex="-1">C. <strong>優先級低（長期 Roadmap）</strong> <a class="header-anchor" href="#c-優先級低-長期-roadmap" aria-label="Permalink to &quot;C. **優先級低（長期 Roadmap）**&quot;">​</a></h3><ol start="7"><li><p><strong>A/B Testing Infrastructure for Harness Changes</strong><br> 前提：需要 session-level keep-rate 或代碼保留率統計<br> 來源：Cursor 的線上評估法</p></li><li><p><strong>跨 Harness 相容性警告系統</strong><br> 前提：若未來支援其他 harness（Cursor、Codex）<br> 動作：動態檢測 tool schema mismatch 並警告可能的降級<br> 來源：V4A format + Arbiter 架構分析</p></li></ol><hr><h2 id="研究發現的可信度評估" tabindex="-1">研究發現的可信度評估 <a class="header-anchor" href="#研究發現的可信度評估" aria-label="Permalink to &quot;研究發現的可信度評估&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>評價</th></tr></thead><tbody><tr><td><strong>證據強度</strong></td><td><strong>高</strong>。Terminal-Bench 2.0、Cursor、LangChain、Anthropic 四個獨立來源量化相同現象</td></tr><tr><td><strong>機制理解</strong></td><td><strong>高</strong>。Codex V4A、Anthropic system-reminder、Claude Code memory 的具體實施細節已公開</td></tr><tr><td><strong>反方論述</strong></td><td><strong>弱</strong>。NLAH 論文未驗證跨模型；MCP 解決工具發現但未解決 schema overfitting</td></tr><tr><td><strong>可重現性</strong></td><td><strong>高</strong>。Terminal-Bench 開源、Codex 開源碼、公開數據足以複現</td></tr><tr><td><strong>適用範圍</strong></td><td><strong>廣</strong>。發現適用任何 multi-model agent 平台；不限 Claude Code 用戶</td></tr></tbody></table><hr><h2 id="總結" tabindex="-1">總結 <a class="header-anchor" href="#總結" aria-label="Permalink to &quot;總結&quot;">​</a></h2><p>Model-Harness-Fit 是 2026 年 agent 設計的隱藏杠桿。與其追求跨 harness 通用性，不如承認「each model + harness = different product」並據此優化。</p><p>cc-workspace 已內化此觀點（CLAUDE.md、Skills、subagent-strategy 都對齐 Claude Code 特定設計），現階段重點應轉向：</p><ol><li><strong>驗證當前 harness 對 Opus 4.7 仍最優</strong></li><li><strong>建立 per-model evaluation 防止回歸</strong></li><li><strong>審計哪些元件已過時需清除</strong></li></ol><p>跨 harness 支援（如 Cursor、Codex）應視為「不同產品」而非「參數調整」，成本遠高於單一 harness 最優化。</p><hr><h2 id="引用索引" tabindex="-1">引用索引 <a class="header-anchor" href="#引用索引" aria-label="Permalink to &quot;引用索引&quot;">​</a></h2><p><strong>關鍵推文</strong>：@nicbstme 2026-05-04（Model-Harness-Fit 命名與綜合論述）</p><p><strong>相關 cc-workspace 檔案</strong>：</p><ul><li><code>.claude/rules/core.md</code> § 實作前假設</li><li><code>.claude/rules/subagent-strategy.md</code> § PGE 拓撲</li><li><code>.claude/refs/harness-design.md</code> § 反模式</li><li><code>.claude/refs/model-selection-grid.md</code> § 模型選擇</li><li><code>.claude/skills/opus-pilot/SKILL.md</code> § 推理配置</li></ul><hr><p><strong>Last updated</strong>: 2026-05-09<br><strong>Next review suggested</strong>: 2026-11-09（harness evolution 年度檢查）</p>',76)])])}const u=r(n,[["render",a]]);export{p as __pageData,u as default};
